package com.jahid.multiplusmail;
import android.app.*;import android.content.*;import android.os.*;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;
public class LoginPickerActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_login_picker);bind(R.id.rowGoogle,"Gmail","gmail","https://accounts.google.com/");bind(R.id.rowOutlook,"Outlook","outlook","https://login.live.com/login.srf");bind(R.id.rowYahoo,"Yahoo","yahoo","https://mail.yahoo.com/");bind(R.id.rowExchange,"Exchange","exchange","https://login.microsoftonline.com/");bind(R.id.rowOther,"Other Mail","other","https://accounts.google.com/signin/v2/identifier?service=mail");}
Class<?> activityForSlot(int slot){try{if(slot<1)slot=1;if(slot>50)slot=50;return Class.forName("com.jahid.multiplusmail.ContainerActivity"+slot);}catch(Exception e){return ContainerActivity1.class;}}
void bind(int row,String def,String provider,String url){findViewById(row).setOnClickListener(v->askName(def,provider,url));}
void askName(String def,String provider,String url){int slot=MailStorage.nextSlot(this);if(slot==-1){new AlertDialog.Builder(this).setTitle("Limit reached").setMessage("Extended isolated version supports 50 saved containers. Delete one container first.").setPositiveButton("OK",null).show();return;}EditText input=new EditText(this);input.setText(def);input.setSingleLine(true);new AlertDialog.Builder(this).setTitle("Container Name").setView(input).setPositiveButton("Continue",(d,w)->{String name=input.getText().toString().trim();if(name.isEmpty())name=def;String id=provider+"_"+System.currentTimeMillis();MailStorage.add(this,new MailAccount(id,name,provider,url,slot));MailAccount a=new MailAccount(id,name,provider,url,slot);Intent i=new Intent(this,activityForSlot(slot));i.putExtra("id",id);i.putExtra("name",name);i.putExtra("provider",provider);i.putExtra("url",url);i.putExtra("slot",slot);startActivity(i);finish();}).setNegativeButton("Cancel",null).show();}}